// // This module decrements the 2-bit binary counter on every positive edge of the clock when the enable signal is high. If the enable signal is low, the counter should decrement its value. The counter should reset to FF when the reset input is high.
module binary_counter (
    input clk,
    input rst,
    input en,
    output reg [1:0] count
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 2'b00;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
